export async function getAllProducts() {
  // Simulate a database query.
  await new Promise(resolve => setTimeout(resolve, 100));

  return [
    { id: 1, name: 'Laptop', price: 999, inventory: 24, availability: 'In stock' },
    { id: 2, name: 'Phone', price: 699, inventory: 0, availability: 'Backorder' },
    { id: 3, name: 'Tablet', price: 499, inventory: 11, availability: 'In stock' },
    { id: 4, name: 'Headphones', price: 199, inventory: 48, availability: 'In stock' },
    { id: 5, name: 'Watch', price: 299, inventory: 6, availability: 'Limited' }
  ];
}

export const getCachedProducts = unstable_cache(
  getAllProducts,
  ['products'],
  {
    tags: ['products']
  }
);

